import React, { useState } from 'react';
import { useAuth } from './AuthContext';
import LoginModal from './LoginModal';
import RegisterModal from './RegisterModal';
import CartModal from './CartModal';
import './Header.css';

const Header = () => {
    const [showLogin, setShowLogin] = useState(false);
    const [showRegister, setShowRegister] = useState(false);
    const [showCart, setShowCart] = useState(false);
    const { user, logout } = useAuth();

    return (
        <>
            <header>
                <div className="container">
                    <nav>
                        <div className="logo">
                            <a href="/">
                                <h1>Auto<span>Vip</span></h1>
                            </a>
                        </div>
                        <ul className="nav-menu">
                            <li><a href="/">Trang Chủ</a></li>
                            <li><a href="#cars">Xe</a></li>
                            <li><a href="#brands">Thương Hiệu</a></li>
                            {user && user.role === 'admin' && (
                                <li><a href="/admin">Quản Lý</a></li>
                            )}
                        </ul>
                        <div className="nav-buttons">
                            {/* Icon giỏ hàng - chỉ hiện khi đã đăng nhập */}
                            {user && (
                                <button 
                                    onClick={() => setShowCart(true)} 
                                    className="cart-icon"
                                    style={{
                                        background: 'none',
                                        border: 'none',
                                        fontSize: '24px',
                                        cursor: 'pointer',
                                        position: 'relative',
                                        marginRight: '15px',
                                        transition: 'transform 0.3s',
                                        color: '#333'
                                    }}
                                    onMouseEnter={(e) => e.target.style.transform = 'scale(1.1)'}
                                    onMouseLeave={(e) => e.target.style.transform = 'scale(1)'}
                                >
                                    🛒
                                </button>
                            )}

                            {user ? (
                                <>
                                    <span className="welcome-text">
                                        👋 Xin chào, <strong>{user.fullname}</strong>
                                    </span>
                                    <button onClick={logout} className="btn-logout">
                                        Đăng Xuất
                                    </button>
                                </>
                            ) : (
                                <>
                                    <button onClick={() => setShowLogin(true)} className="btn-login">
                                        Đăng Nhập
                                    </button>
                                    <button onClick={() => setShowRegister(true)} className="btn-register">
                                        Đăng Ký
                                    </button>
                                </>
                            )}
                        </div>
                    </nav>
                </div>
            </header>

            <LoginModal 
                isOpen={showLogin}
                onClose={() => setShowLogin(false)}
                onSwitchToRegister={() => {
                    setShowLogin(false);
                    setShowRegister(true);
                }}
            />

            <RegisterModal 
                isOpen={showRegister}
                onClose={() => setShowRegister(false)}
                onSwitchToLogin={() => {
                    setShowRegister(false);
                    setShowLogin(true);
                }}
            />

            <CartModal 
                isOpen={showCart}
                onClose={() => setShowCart(false)}
            />
        </>
    );
};

export default Header;
